# ============================================

# تسجيل الأخطاء
logging.basicConfig(level=logging.ERROR)
logger = logging.getLogger(__name__)

# إعدادات الأداء الحرجة
MAX_CONCURRENT_REQUESTS = 1  # طلب واحد فقط في نفس الوقت (يمنع الضغط)
REQUEST_TIMEOUT = 45  # وقت المهلة بالثواني
CONNECTION_LIMIT = 2  # عدد الاتصالات المتزامنة
MAX_MEMORY_MB = 1024  # الحد الأقصى للذاكرة 1 جيجابايت

# Semaphore للتحكم في الطلبات
request_semaphore = Semaphore(MAX_CONCURRENT_REQUESTS)

# تعيين حدود الموارد
def set_resource_limits():
    try:
        resource.setrlimit(resource.RLIMIT_AS, (MAX_MEMORY_MB * 1024 * 1024, MAX_MEMORY_MB * 1024 * 1024))
        resource.setrlimit(resource.RLIMIT_CPU, (60, 60))  # حد CPU 60 ثانية
    except:
        pass

set_resource_limits()

# دالة التحقق من الذاكرة
def check_memory_usage():
    try:
        process = psutil.Process()
        mem_mb = process.memory_info().rss / 1024 / 1024
        if mem_mb > MAX_MEMORY_MB * 0.7:
            logger.warning(f"Memory usage: {mem_mb:.0f}MB, cleaning...")
            gc.collect()
            gc.collect()
            return True
        return False
    except:
        return False

# تشغيل تنظيف الذاكرة كل 10 ثواني
def periodic_cleanup():
    check_memory_usage()
    return True

