C2C = {
    "USD": "US", "CAD": "CA", "INR": "IN", "AED": "AE",
    "HKD": "HK", "GBP": "GB", "CHF": "CH",
}

ADDRESS_BOOK = {
    "US": {"address1": "123 Main St", "city": "New York", "postalCode": "10001", 
           "zoneCode": "NY", "countryCode": "US", "phone": "2125550199"},
    "CA": {"address1": "88 Queen St", "city": "Toronto", "postalCode": "M5H2J3", 
           "zoneCode": "ON", "countryCode": "CA", "phone": "4165550199"},
    "GB": {"address1": "221B Baker St", "city": "London", "postalCode": "NW1 6XE", 
           "zoneCode": "LND", "countryCode": "GB", "phone": "2079460123"},
    "DEFAULT": {"address1": "123 Main St", "city": "New York", "postalCode": "10001", 
                "zoneCode": "NY", "countryCode": "US", "phone": "2125550199"},
}

def pick_addr(url):
    domain = urlparse(url).netloc
    tld = domain.split('.')[-1].upper()
    return ADDRESS_BOOK.get(tld, ADDRESS_BOOK["DEFAULT"])

def get_random_name():
    first_names = ["James", "John", "Robert", "Michael", "William", "David", "Mary", "Patricia"]
    last_names = ["Smith", "Johnson", "Williams", "Brown", "Jones", "Garcia", "Miller", "Davis"]
    return (random.choice(first_names), random.choice(last_names))

def generate_email(first, last):
    domains = ["gmail.com", "yahoo.com", "outlook.com"]
    return f"{first.lower()}.{last.lower()}@{random.choice(domains)}"

def parse_proxy(proxy_str):
    if not proxy_str:
        return None
    parts = proxy_str.split(':')
    if len(parts) == 2:
        return f"http://{parts[0]}:{parts[1]}"
    elif len(parts) == 4:
        return f"http://{parts[2]}:{parts[3]}@{parts[0]}:{parts[1]}"
    return None

def extract_between(text, start, end):
    try:
        if start in text:
            parts = text.split(start, 1)
            if len(parts) > 1 and end in parts[1]:
                return parts[1].split(end, 1)[0]
    except:
        pass
    return None

def is_captcha_required(text):
    if not text:
        return False
    indicators = ['CAPTCHA_REQUIRED', 'hcaptcha', 'h-captcha', 'captcha required']
    return any(i.upper() in text.upper() for i in indicators)

def clean_response(message):
    if not message:
        return "UNKNOWN_ERROR"
    message = str(message)
    patterns = [
        r'(PAYMENTS_[A-Z_]+)',
        r'(CARD_[A-Z_]+)',
        r'([A-Z]+_[A-Z]+_[A-Z_]+)',
        r'{"code":"([^"]+)"',
    ]
    for pattern in patterns:
        match = re.search(pattern, message, re.IGNORECASE)
        if match:
            code = match.group(1) if isinstance(match.group(1), str) else match.group(1)
            if code and len(code) < 50:
                return code.strip()
    return message[:50]

