app = Flask(__name__)

@app.errorhandler(Exception)
def handle_exception(e):
    return jsonify({
        "error": str(e),
        "status": False,
        "Gateway": "UNKNOWN",
        "Price": 0.0,
        "Response": f"ERROR: {str(e)}"
    }), 500

@app.route('/shopify', methods=['GET'])
def shopify_checker():
    try:
        site = request.args.get('site')
        cc_string = request.args.get('cc')
        proxy_str = request.args.get('proxy')
        
        if not site:
            return jsonify({"error": "Missing 'site'", "status": False}), 400
        
        if not cc_string:
            return jsonify({"error": "Missing 'cc'", "status": False}), 400
        
        parts = cc_string.split('|')
        if len(parts) != 4:
            return jsonify({"error": "Invalid CC format", "status": False}), 400
        
        cc, mes, ano, cvv = parts
        variant_id = request.args.get('variant')
        
        loop = asyncio.new_event_loop()
        asyncio.set_event_loop(loop)
        
        try:
            success, message, gateway, price, currency = loop.run_until_complete(
                process_card(cc.strip(), mes.strip(), ano.strip(), cvv.strip(), site, variant_id, proxy_str)
            )
        finally:
            loop.close()
            gc.collect()
        
        return jsonify({
            "Gateway": gateway,
            "Price": float(price) if price else 0.0,
            "Response": clean_response(message),
            "Status": success,
            "cc": cc_string
        })
        
    except Exception as e:
        return jsonify({
            "error": str(e),
            "status": False,
            "Gateway": "UNKNOWN",
            "Price": 0.0,
            "Response": f"ERROR: {str(e)}"
        }), 500

if __name__ == "__main__":
    app.run(host='0.0.0.0', port=5000, debug=False, threaded=True)
